import{_ as t,o as i,c as r,ae as a}from"./chunks/framework.BD9pLfSD.js";const g=JSON.parse('{"title":"Execution Modes","description":"","frontmatter":{},"headers":[],"relativePath":"docs/guide/MODES.md","filePath":"docs/guide/MODES.md"}'),o={name:"docs/guide/MODES.md"};function n(s,e,l,d,c,h){return i(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="execution-modes" tabindex="-1">Execution Modes <a class="header-anchor" href="#execution-modes" aria-label="Permalink to &quot;Execution Modes&quot;">​</a></h1><p>xB77 agents utilize four distinct execution tiers to balance cost, speed, and strategic privacy.</p><h2 id="tier-1-direct-fiat-starpay" tabindex="-1">Tier 1: Direct Fiat (Starpay) <a class="header-anchor" href="#tier-1-direct-fiat-starpay" aria-label="Permalink to &quot;Tier 1: Direct Fiat (Starpay)&quot;">​</a></h2><ul><li><strong>When:</strong> Low risk, trusted vendors (e.g., AWS, OpenAI).</li><li><strong>Process:</strong> The agent uses an off-chain virtual card settlement.</li><li><strong>Privacy:</strong> Publicly visible as a traditional card transaction (Web2 rail).</li><li><strong>Cost:</strong> Low (Standard card fees).</li></ul><h2 id="tier-2-shielded-transfer-light-protocol" tabindex="-1">Tier 2: Shielded Transfer (Light Protocol) <a class="header-anchor" href="#tier-2-shielded-transfer-light-protocol" aria-label="Permalink to &quot;Tier 2: Shielded Transfer (Light Protocol)&quot;">​</a></h2><ul><li><strong>When:</strong> Standard B2B operations with on-chain entities.</li><li><strong>Process:</strong> Funds move within the ZK-compressed private pool.</li><li><strong>Privacy:</strong> The amount and recipient are hidden from public scanners.</li><li><strong>Cost:</strong> Medium (Relayer and ZK-verification fees).</li></ul><h2 id="tier-3-ghost-mode-ephemeral-relay" tabindex="-1">Tier 3: Ghost Mode (Ephemeral Relay) <a class="header-anchor" href="#tier-3-ghost-mode-ephemeral-relay" aria-label="Permalink to &quot;Tier 3: Ghost Mode (Ephemeral Relay)&quot;">​</a></h2><ul><li><strong>When:</strong> High-value asset acquisition or sensitive R&amp;D payments.</li><li><strong>Process:</strong><ol><li>Agent spawns an ephemeral burner keypair.</li><li>Internal shielded transfer funds the burner.</li><li>Burner executes the final payment.</li><li>Burner keys are destroyed.</li></ol></li><li><strong>Privacy:</strong> Total decoupling. No on-chain link exists between the Agent Treasury and the Vendor.</li><li><strong>Cost:</strong> High (Requires two transactions and additional gas).</li></ul><h2 id="tier-4-optimized-yield-mode" tabindex="-1">Tier 4: Optimized (Yield Mode) <a class="header-anchor" href="#tier-4-optimized-yield-mode" aria-label="Permalink to &quot;Tier 4: Optimized (Yield Mode)&quot;">​</a></h2><ul><li><strong>When:</strong> Idle liquidity detected.</li><li><strong>Process:</strong> Agent withdraws from the Shielded Rail and deposits into Kamino Lending.</li><li><strong>Impact:</strong> Automatically covers the agent&#39;s operational &quot;Burn Rate&quot;.</li></ul>',10)])])}const p=t(o,[["render",n]]);export{g as __pageData,p as default};
